-- CREATE
  ('a535e0b8-bb7c-4be0-a690-694f269d4d9f', '1.1', 'Create', 'Happy path',
   'Create a prime contract with all fields filled',
   'Confirms full creation flow: required fields, optional financial fields, status defaults to Draft.',
   'Logged in as test1@mail.com on project 67.',
   E'1. Navigate to /67/prime-contracts\n2. Click "Create".\n3. Fill "Contract #" with **PC-TEST-001**.\n4. Fill "Title" with **Test Prime Contract - Full**.\n5. Set "Original Contract Value" to **500000**.\n6. Set "Start Date" to **2026-06-01**.\n7. Set "End Date" to **2027-05-31**.\n8. Set "Retention %" to **10**.\n9. Click "Save".',
   'Browser redirects to the new contract detail page. Status badge shows "Draft". Original Contract Value shows $500,000.00. No error toast.',
   'HIGH', 'scenario', '/67/prime-contracts/new'),

  ('a535e0b8-bb7c-4be0-a690-694f269d4d9f', '1.2', 'Create', 'Required field validation',
   'Submitting the create form without required fields shows validation errors',
   'Confirms Contract # and Title are enforced as required.',
   'Create form open at /67/prime-contracts/new.',
   E'1. Navigate to /67/prime-contracts/new\n2. Leave "Contract #" blank.\n3. Leave "Title" blank.\n4. Click "Save".',
   'Form does not submit. Inline validation errors appear on "Contract #" and "Title" fields. No navigation away from the form.',
   'HIGH', 'scenario', '/67/prime-contracts/new'),

  ('a535e0b8-bb7c-4be0-a690-694f269d4d9f', '1.3', 'Create', 'Duplicate contract number',
   'Creating a contract with an already-used contract number shows an error',
   'API enforces unique contract_number per project; confirms the error surfaces in the UI.',
   'A contract with number PC-TEST-001 already exists in project 67.',
   E'1. Navigate to /67/prime-contracts/new\n2. Fill "Contract #" with **PC-TEST-001**.\n3. Fill "Title" with **Duplicate Test**.\n4. Click "Save".',
   'Form shows an error message "Contract number already exists for this project". No new contract is created.',
   'HIGH', 'scenario', '/67/prime-contracts/new'),

  ('a535e0b8-bb7c-4be0-a690-694f269d4d9f', '1.4', 'Create', 'Negative contract value rejected',
   'Entering a negative original contract value is blocked',
   'Validation schema enforces min(0) on original_contract_value.',
   'Create form open.',
   E'1. Navigate to /67/prime-contracts/new\n2. Fill "Contract #" with **PC-VAL-001**.\n3. Fill "Title" with **Validation Test**.\n4. Enter **-1000** in "Original Contract Value".\n5. Click "Save".',
   'Form shows a validation error on the Original Contract Value field. No contract is created.',
   'MEDIUM', 'scenario', '/67/prime-contracts/new'),

