   'Page exits edit mode. Title now shows "Updated Contract Title". Original Contract Amount shows $600,000.00. Payment Terms shows "Net 30". After page refresh, all changes persist.',
   'HIGH', 'scenario', '/67/prime-contracts'),

  ('a535e0b8-bb7c-4be0-a690-694f269d4d9f', '3.2', 'Edit', 'Duplicate number on edit blocked',
